exercise.solution:
function formatPrice(price: number, currency: string = '$'): string {
  return `${currency}${price.toFixed(2)}`;
}

const applyDiscount = (price: number, discountPercent: number): number => {
  return price * (1 - discountPercent / 100);
};

const original = 49.99;
const discounted = applyDiscount(original, 20);
console.log(formatPrice(original));       // $49.99
console.log(formatPrice(discounted, '€')); // €39.99
